w('senior-qin-han.json', {"eraId":"senior-qin-han","eraName":"秦汉统一多民族国家","playerRole":"秦始皇嬴政","acts":[
A("act-1","战国末年",False,"战国末期，七雄争霸已经持续了两百多年。你嬴政13岁即位为秦王，22岁亲政。在吕不韦和嫪毐之乱平定后，你开始掌握秦国的绝对权力。秦经过商鞅变法已是最强大的国家，统一天下只是时间问题。",[N("李斯","大王，臣有一统天下之策。秦国经过百年变法，国力远超六国，此时正是统一良机。","斯"),N("韩非","法者，编著之图籍，设之于官府，而布之于百姓者也。以法治国，则国强。","非")],[
D("d1","六国虽强，但各自为政，互相攻伐。秦国必须抓住时机一举统一天下，结束数百年的战乱。","我","嬴",91,"秦统一六国","秦国经过商鞅变法后国力最强。秦始皇嬴政从公元前230年开始，先后灭韩、赵、魏、楚、燕、齐六国，于前221年统一天下。","统一天下，结束战乱。"),
D("d2","韩非的法家思想对我影响很大。以法治国、以势治国、以术治国，三者缺一不可。","我","嬴",89,"韩非思想","韩非集法家大成，提出法治、势治、术治三位一体。秦始皇深得其精髓，以法家思想治国。可惜韩非入秦后不久即被害死。","法家思想成就帝业。"),
D("d3","李斯是难得的治国之才。他的谏逐客书让我收回成命，留住了大量人才。","我","嬴",87,"李斯的谏逐客书","秦始皇曾下令驱逐六国客卿。李斯上《谏逐客书》力陈客卿对秦国的贡献，秦始皇收回成命。","人才是立国之本。"),
D("d4","秦国的军队是天下最强大的。秦军有百万之众，武器精良，训练有素。","我","嬴",85,"秦军","秦国经过长期军事建设，拥有一支约百万人的强大军队。秦军兵器标准化程度很高，管理制度严格。","秦军天下无敌。"),
D("d5","统一天下后最重要的工作是建立一套全新的制度。分封制已经证明是失败的。","我","嬴",88,"制度设计","秦始皇统一后废分封、立郡县，统一文字、货币、度量衡，建立了一套中央集权制度。","制度创新影响深远。"),
D("d6","先祖的基业已经奠定。秦孝公任用商鞅变法，秦国由此强大。我站在巨人的肩膀上。","我","嬴",83,"秦国基业","秦国从秦孝公任用商鞅变法开始，经过六代君主的积累，到秦始皇终于完成了统一大业。","百年基业，一朝实现。")]),

A("act-2","灭六国",False,"从前230年到前221年，你嬴政用了十年时间先后灭韩、赵、魏、楚、燕、齐六国。统一战争波澜壮阔。",[N("李斯","王翦将军大破楚军，楚王负刍被俘。六国已灭其五，统一在即。","斯"),N("王翦","大王，末将愿率六十万大军伐楚。楚地辽阔，非重兵不可取胜。","王")],[
D("d1","灭韩之后取赵，赵国名将李牧已死，赵国不堪一击。","我","嬴",90,"灭韩赵","秦灭六国的顺序是韩、赵、魏、楚、燕、齐。韩最小最先灭；赵国名将李牧死后很快也被灭。","六国逐一灭亡。"),
D("d2","灭楚之战最为艰难。王翦率六十万大军才最终攻克。","我","嬴",88,"灭楚之战","灭楚之战是秦灭六国中最艰难的一战。王翦率六十万大军出征，以持久战略消耗楚军后发起总攻。","灭楚之战最为激烈。"),
D("d3","齐国最后投降，未经大战便归入秦版图。齐国长期偏安，缺乏战备。","我","嬴",84,"灭齐","齐国是六国中最后一个被灭的国家。由于长期不参与战国纷争，军备废弛，秦军一到便投降。","齐国不战而降。"),
D("d4","统一六国用了十年。期间秦军展现了无与伦比的战斗力和组织力。","我","嬴",87,"统一战争","秦灭六国从公元前230年到前221年，历时十年。秦国的强大国力和高效军事组织是取胜的关键。","十年统一天下。"),
D("d5","李斯在统一过程中负责外交和战略策划，功劳卓著。","我","嬴",85,"李斯的贡献","李斯在统一战争中为秦始皇出谋划策，利用外交手段瓦解六国联盟。","李斯功不可没。"),
D("d6","六国灭亡后，天下归于一统。但如何治理这个前所未有的庞大帝国，是更大的挑战。","我","嬴",89,"治理挑战","统一只是第一步，如何治理一个前所未有的庞大帝国是更大的挑战。秦始皇选择了中央集权的郡县制。","治理比统一更难。")]),

A("act-3","统一制度",False,"统一天下后，你嬴政推行了一系列统一措施：统一文字为小篆，统一货币为秦半两，统一度量衡，统一车轨。这些措施深刻影响了中国两千年的历史。",[N("李斯","臣已主持统一文字工作，以小篆为标准字体，全国通行。","斯"),N("史","司马迁将在后来记录这一切。大一统的思想从此植根于华夏大地。","史")],[
D("d1","书同文、车同轨、量同衡。统一制度是维护国家长治久安的根基。","我","嬴",93,"统一措施","秦始皇推行书同文、车同轨、统一度量衡等措施，消除了六国遗留下来的制度差异，为统一国家的管理奠定了基础。","统一制度意义深远。"),
D("d2","李斯主持文字统一工作，以小篆为标准字体。文字统一是文化统一的核心。","我","嬴",90,"书同文","秦始皇命李斯等人统一文字，以小篆为标准字体。文字的统一极大地促进了各地文化交流和中央政令的推行。","文字统一文化统一。"),
D("d3","统一货币为秦半两钱，外圆内方，象征天圆地方。货币统一促进了经济发展。","我","嬴",88,"统一货币","秦始皇废除六国旧币，统一使用秦半两钱（圆形方孔钱）。货币的统一促进了全国范围内的商品流通和经济发展。","货币统一经济繁荣。"),
D("d4","统一度量衡后，全国贸易更加便利。各地百姓不再为度量不一而争执。","我","嬴",85,"统一度量衡","秦始皇统一了全国的度量衡标准，制定了一套严格的度量衡制度。这为全国范围的征税和贸易提供了统一标准。","度量统一便利贸易。"),
D("d5","车同轨后，全国的道路更加规整，交通运输效率大大提高。","我","嬴",83,"车同轨","秦始皇统一了车轨宽度，修建了以咸阳为中心的全国性道路网络（驰道和直道）。","交通网络四通八达。"),
D("d6","这些统一措施的影响远超秦朝本身，它们奠定了中国作为统一国家的制度基础。","我","嬴",92,"深远影响","秦始皇的统一措施深刻影响了中国两千年的政治制度和文化传统。大一统成为中国历史的常态。","影响延续两千年。")]),

A("act-4","郡县制与中央集权",True,"你嬴政废除了分封制，推行郡县制，将全国分为三十六郡，郡下设县。所有官员由中央任命。这是中国政治制度的根本性变革。",[N("李斯","大王废除分封立郡县，这是万世之功。天下一统，必须由中央直接管理。","斯"),N("史","郡县制开创了中国两千年的地方行政制度。此后历朝虽有调整，但基本框架未变。","史")],[
D("d1","废除分封制，推行郡县制。天下一统，必须由中央直接管理，不能再让诸侯割据。","我","嬴",95,"郡县制","秦始皇废除分封制，推行郡县制，将全国分为三十六郡（后增至四十余郡），郡下设县。所有官员由中央任命，可随时调换。","郡县制影响两千年。"),
D("d2","朝中设三公九卿制：丞相管行政、太尉管军事、御史大夫管监察。分工明确，相互制衡。","我","嬴",90,"三公九卿","秦始皇建立了三公九卿制：丞相管行政、太尉管军事、御史大夫管监察。九卿分管各部门事务。","官僚制度建立。"),
D("d3","在中央设立丞相制度，丞相是百官之首，协助皇帝处理国家大事。","我","嬴",87,"丞相制度","秦朝建立了较为完善的官僚体系，丞相是中央政府的最高行政长官。这一制度为后世所沿用。","官僚体系完善。"),
D("d4","郡县制的推行遭到部分旧贵族的反对。但我坚信，郡县制比分封制更有利于国家的长治久安。","我","嬴",88,"推行阻力","郡县制的推行遭到了部分旧六国贵族和秦国内部保守势力的反对。秦始皇坚持推行，以强有力的手段确保实施。","改革需要决心。"),
D("d5","为了防止六国遗民作乱，我下令收缴天下兵器，运到咸阳熔铸成十二金人。","我","嬴",83,"收缴兵器","秦始皇统一后下令收缴天下兵器，运到咸阳熔铸成十二个大型铜人（金人），既消除了武装反抗的隐患，又展示了帝国威严。","收缴兵器消除隐患。"),
D("d6","朕为始皇帝，后世以数计，二世、三世至于万世，传之无穷。","我","嬴",94,"始皇帝","秦始皇自认为功过三皇五帝，创皇帝称号，自称始皇帝，希望秦朝能延续万世。","皇帝称号由此开始。")]),

A("act-5","万里长城",False,"为防御北方匈奴的侵扰，你嬴政下令将秦、赵、燕三国原有的长城连接起来，修筑西起临洮、东至辽东的万里长城。这是人类历史上最伟大的建筑工程之一。",[N("李斯","蒙恬将军率三十万大军北击匈奴，同时修筑长城。这一工程虽艰苦，但关系到帝国的安全。","斯"),N("史","长城不仅是军事工程，更是中华民族坚韧不拔精神的象征。","史")],[
D("d1","命蒙恬率三十万大军北击匈奴，同时修筑万里长城。匈奴南下侵扰，必须加以防御。","我","嬴",91,"修筑长城","秦始皇命蒙恬率三十万大军北击匈奴，并将秦、赵、燕三国旧长城连接起来，修筑了西起临洮、东至辽东的万里长城。","万里长城防御匈奴。"),
D("d2","修长城征用了大量民力，百姓负担沉重。但国防安全是重中之重。","我","嬴",80,"修长城的代价","修筑长城征用了数十万民夫，许多劳工死于繁重的劳役。长城的修筑虽然是国防需要，但也加重了百姓的负担。","伟大工程背后的代价。"),
D("d3","蒙恬收复河套地区，设置四十四县，移民实边。这巩固了北方边防。","我","嬴",87,"收复河套","蒙恬击败匈奴后收复了河套地区，秦在此设置四十四县，迁徙人民充实边防。","河套地区纳入版图。"),
D("d4","长城的修建展示了秦朝的组织能力和工程水平。尽管代价沉重，但它的战略价值无可替代。","我","嬴",85,"长城的意义","长城作为军事防御工程在战略上具有重要价值。它不仅是秦朝的防线，也成为后世各朝的北方屏障。","战略价值无可替代。"),
D("d5","北方的匈奴虽然被击退，但他们随时可能卷土重来。长城是我们最好的防线。","我","嬴",83,"匈奴威胁","匈奴是秦朝北方的主要威胁。秦始皇派蒙恬北击匈奴并修筑长城，暂时缓解了匈奴的威胁。","匈奴威胁需要持续应对。"),
D("d6","万里长城将成为后世万代之利。它的历史价值将远超它的军事价值。","我","嬴",86,"长城的历史价值","万里长城是中国古代最伟大的建筑工程之一，后来成为中华民族的象征和世界文化遗产。","长城是中华文明的象征。")]),

A("act-6","焚书坑儒",False,"为了统一思想，你嬴政下令焚毁除秦史和医药卜筮农书之外的民间藏书，并坑杀了四百六十多名方士和儒生。这一举措成为千古争议。",[N("李斯","天下已定，法令出一。百姓应该以吏为师，学习法律，而非私学古书。","斯"),N("史","焚书坑儒确实是中国文化史上的一次浩劫。许多珍贵的先秦典籍因此失传。","史")],[
D("d1","天下已定，必须统一思想。民间藏书太多，百姓各执己见，不利于国家的统一管理。","我","嬴",75,"焚书","秦始皇采纳李斯的建议，下令焚毁民间收藏的诗书和诸子百家著作（医药、卜筮、农书除外）。这一政策严重损害了文化传承。","焚书是文化浩劫。"),
D("d2","坑儒之事，是针对那些妖言惑众的方士。并非专门针对儒家学者。","我","嬴",70,"坑儒","秦始皇坑杀了四百六十多名方士（后被附会为儒生），原因是他们蛊惑人心、诽谤朝政。这一行为历来受到严厉批评。","坑儒是暴政表现。"),
D("d3","以法为教、以吏为师。百姓只需要学习法律，不需要读那些古书。","我","嬴",72,"以法为教","秦始皇推行以法为教、以吏为师的政策，试图通过法律教育统一思想。但这种极端做法效果适得其反。","极端手段的恶果。"),
D("d4","历史的评价是多元的。统一思想是必要的，但手段不应如此极端。","我","嬴",78,"历史评价","焚书坑儒历来受到严厉批评。它严重损害了先秦文化典籍的传承，是中国文化史上的重大损失。","暴力手段不可取。"),
D("d5","许多珍贵的先秦典籍因此失传。这是我最大的遗憾之一。","我","嬴",76,"文化损失","秦始皇焚书导致大量先秦典籍失传。虽然部分典籍通过其他途径保存下来，但损失仍然巨大。","文化损失无法弥补。"),
D("d6","李斯提出焚书建议时说，不如此则天下思想纷乱，法令难以推行。他的理由有几分道理，但手段过于极端。","我","嬴",74,"李斯建议","李斯认为焚书是统一思想的必要手段。他的出发点是维护国家统一，但手段过于激进。","出发点正确手段错误。")]),

A("act-7","秦的暴政与灭亡",False,"繁重的徭役和严苛的刑罚让百姓苦不堪言。你嬴政晚年沉迷于求仙问药，大兴土木。秦朝的统治基石开始动摇。",[N("李斯","陛下，徭役太重，百姓不堪其苦。长此以往，恐有民变。","斯"),N("史","秦法之严，旷古未有。轻罪重罚，动辄连坐。百姓苦秦久矣。","史")],[
D("d1","阿房宫和骊山陵墓的修建征用了大量民力。虽然我想留下千古帝王的印记，但确实加重了百姓的负担。","我","嬴",76,"繁重徭役","秦始皇修建阿房宫和骊山陵墓征用了大量民夫。加上修长城、修驰道等工程，全国服徭役者超过两百万。沉重的徭役是百姓苦不堪言。","徭役沉重民不聊生。"),
D("d2","秦法严苛，轻罪重罚，动辄连坐。百姓生活在恐惧之中。","我","嬴",73,"严刑峻法","秦朝法律严苛，连坐制度使得一人犯法则全家受罚。虽然严刑峻法有助于维护社会秩序，但也引发了广泛的不满。","法律过于严酷。"),
D("d3","我四处巡游，一方面是视察各地，另一方面也是为了寻找仙人。求仙问药确实耗费了大量资源。","我","嬴",71,"求仙问药","秦始皇晚年热衷于求仙问药，多次派方士出海寻找仙人，希望获得长生不老药。这些活动耗费了大量资源。","求仙是秦始皇的执念。"),
D("d4","沙丘之变，赵高与李斯篡改遗诏，赐死扶苏，立胡亥为帝。秦朝的命运从此急转直下。","我","嬴",82,"沙丘之变","公元前210年秦始皇在巡游途中病逝于沙丘。宦官赵高与丞相李斯密谋篡改遗诏，赐死长子扶苏，立幼子胡亥为帝。","沙丘之变改变历史。"),
D("d5","我最大的失误是未能妥善安排继承问题。扶苏仁厚，本是最好的继承人。","我","嬴",79,"继承问题","秦始皇生前未能明确立储。扶苏虽被派往北方监军，但并未正式被立为太子。这给赵高的阴谋留下了空间。","继承问题酿成大祸。"),
D("d6","秦朝虽然二世而亡，但它的制度遗产影响了两千年。郡县制、统一文字货币度量衡，这些贡献不可磨灭。","我","嬴",88,"秦的遗产","秦朝虽然仅存15年就灭亡了，但它建立的中央集权制度、统一文字货币度量衡等措施深刻影响了中国两千年的历史。","制度遗产永续流传。")]),

A("act-8","楚汉之争",True,"秦朝灭亡后，项羽和刘邦展开争夺天下的楚汉之争。你以叙述者视角见证了这场历时四年的权力角逐。最终刘邦以弱胜强，建立了汉朝。",[N("史","楚汉之争是中国历史上最精彩的权力争夺之一。项羽虽强但刚愎自用，刘邦虽弱但善于用人。","史"),N("汉","汉","善用人才者胜，刚愎自用者败。这是楚汉之争给后人最重要的启示。","汉")],[
D("d1","秦末大泽乡起义爆发，陈胜吴广首举义旗。天下响应，六国遗民纷纷复国。","汉","汉",87,"陈胜吴广起义","公元前209年陈胜吴广在大泽乡起义，喊出王侯将相宁有种乎的豪言。虽然起义很快失败，但掀起了反秦浪潮。","反秦浪潮席卷天下。"),
D("d2","项羽破釜沉舟，在巨鹿之战中以少胜多，大破秦军主力。此战奠定了楚军的霸主地位。","汉","汉",90,"巨鹿之战","项羽在巨鹿之战中破釜沉舟，以五万楚军击败四十万秦军主力。此战是军事史上以少胜多的经典战例。","破釜沉舟背水一战。"),
D("d3","刘邦率先攻入咸阳，接受秦王子婴投降。但他约法三章，赢得了关中百姓的拥护。","汉","汉",92,"刘邦入咸阳","刘邦率先攻入咸阳，接受秦王子婴投降。他废除秦朝苛法，约法三章，赢得关中百姓拥护。这为日后夺取天下奠定了基础。","约法三章赢得民心。"),
D("d4","鸿门宴上，项羽错失杀刘邦的良机。他的妇人之仁最终让他付出了生命的代价。","汉","汉",85,"鸿门宴","鸿门宴是楚汉之争的关键事件。项羽的谋士范增力劝杀刘邦，但项羽犹豫不决，让刘邦借故逃脱。","鸿门宴错失良机。"),
D("d5","韩信背水一战，在井陉之战中以三万新兵击败赵国二十万大军。此战展现了卓越的军事才能。","汉","汉",89,"井陉之战","韩信在井陉之战中以三万新兵背水一战，击败赵国二十万大军。此战展现了韩信高超的军事才能。","韩信军事天才。"),
D("d6","垓下之战，项羽四面楚歌，自刎乌江。一代霸王就此陨落。刘邦最终赢得了天下。","汉","汉",93,"垓下之战","公元前202年刘邦在垓下之战中击败项羽。项羽在四面楚歌中自刎于乌江边。楚汉之争以刘邦胜利告终。","霸王末路英雄悲歌。")]),

A("act-9","汉初休养生息",False,"西汉建立后，你作为汉高祖刘邦，面对百废待兴的局面，采取休养生息的政策，恢复经济，稳定社会。",[N("史","汉初实行休养生息政策，减轻赋税徭役，与民休息。经过六十多年的恢复，到汉武帝时国力达到极盛。","史"),N("汉","汉","打天下靠武力，治天下靠德政。秦朝的教训就在眼前，不可不慎。","汉")],[
D("d1","汉初实行休养生息政策。轻徭薄赋，与民休息。经济逐渐恢复，百姓安居乐业。","汉","汉",89,"休养生息","汉初实行轻徭薄赋、与民休息的政策。汉高祖将田租降为十五税一，文帝时甚至一度免除田租。","休养生息恢复国力。"),
D("d2","秦朝的教训历历在目。暴政亡国，必须以宽仁治国。","汉","汉",87,"以宽仁治国","刘邦吸取秦朝灭亡的教训，采取了较为宽松的统治政策。废除了一些秦朝的苛法，减轻了百姓的负担。","以史为鉴施仁政。"),
D("d3","分封制虽然有问题，但汉初也需要依靠诸侯王的力量来巩固政权。白马之盟约定非刘氏不王。","汉","汉",84,"白马之盟","刘邦在位时封了多位刘姓诸侯王，并与群臣白马之盟约定非刘氏不王。但这并未能阻止后来的七国之乱。","分封与集权的矛盾。"),
D("d4","萧何制定汉律九章，既继承了秦法的框架，又减轻了一些严苛的内容。","汉","汉",86,"汉律九章","萧何参照秦律制定了汉律九章，保留了一些秦法内容，但也减轻了一些过于严苛的处罚。","法律制度逐步完善。"),
D("d5","汉初的经济恢复非常显著。到文景之治时期，社会安定，国库充盈。","汉","汉",88,"文景之治","汉文帝和汉景帝时期（前180-前141年）实行轻徭薄赋政策，社会安定，经济繁荣，史称文景之治。","文景之治是治世典范。"),
D("d6","休养生息六十多年后，到汉武帝即位时，国力已经极为强盛。匈奴的问题可以彻底解决了。","汉","汉",90,"积蓄国力","经过六十多年的休养生息，汉朝国力大增。汉武帝即位后开始对匈奴发动大规模反击。","国力强盛再图武功。")]),

A("act-10","汉武帝的文治武功",False,"汉武帝刘彻在位期间，汉朝国力达到极盛。北击匈奴，通使西域，独尊儒术，创立年号。你见证了这一盛世辉煌。",[N("史","汉武帝北击匈奴，遣张骞通西域，罢黜百家独尊儒术。他的功业影响了整个中国历史。","史"),N("骞","骞","臣奉命出使西域，虽被匈奴扣留十三年，但终于完成了使命。西域诸国愿与大汉通好。","骞")],[
D("d1","汉武帝派卫青、霍去病北击匈奴，解除匈奴对汉朝的威胁。封狼居胥，饮马瀚海。","汉","汉",93,"北击匈奴","汉武帝派卫青、霍去病多次北击匈奴，收复河套地区，打通河西走廊。霍去病封狼居胥山成为千古传颂的壮举。","匈奴之患终被解除。"),
D("d2","张骞出使西域，开辟了丝绸之路。从此东西方文明得以交流互通。","汉","汉",92,"张骞通西域","张骞两次出使西域（前138年、前119年），历经艰险，开辟了从长安到中亚的丝绸之路。","丝绸之路改变世界。"),
D("d3","罢黜百家，独尊儒术。董仲舒的建议被采纳，儒学成为官方正统思想。","汉","汉",88,"独尊儒术","汉武帝采纳董仲舒的建议，罢黜百家独尊儒术，设立太学，以儒家经典为教材选拔官员。儒学从此成为中国官方正统思想。","儒学成为正统。"),
D("d4","汉武帝创立年号制度，第一个年号是建元。这一制度沿用了两千年。","汉","汉",84,"年号制度","汉武帝创立了年号制度，第一个年号为建元（前140年）。年号制度被后世历代王朝沿用。","年号制度沿用两千年。"),
D("d5","汉武帝在位五十四年，前期文治武功彪炳史册，但晚年穷兵黩武，社会矛盾加剧。","汉","汉",86,"武帝功过","汉武帝前期功业辉煌，但连年征战加重了百姓负担，晚年还发生了巫蛊之祸。他临终前下轮台罪己诏反省过失。","功过参半的帝王。"),
D("d6","汉朝在武帝时期疆域空前辽阔，奠定了中国版图的基本格局。","汉","汉",90,"汉朝疆域","汉武帝时期汉朝疆域空前扩大，东至朝鲜半岛，西至中亚，南至越南，北至蒙古高原。","汉朝疆域空前辽阔。")]),

A("act-11","东汉兴衰",True,"西汉末年王莽篡汉建立新朝，很快覆灭。刘秀建立东汉，恢复了汉室统治。东汉在光武中兴后逐渐走向衰落，最终被三国纷争取代。",[N("史","光武帝刘秀以布衣起兵，最终恢复汉室。他是一位杰出的军事家和政治家。","史"),N("骞","东汉时期班超经营西域，丝绸之路更加繁荣。中国文化也开始影响周边国家。","骞")],[
D("d1","王莽篡汉，改制失败，天下大乱。绿林赤眉起义此起彼伏。","汉","汉",85,"王莽篡汉","西汉末年外戚王莽篡汉建立新朝。他的改革措施脱离实际，引发社会动荡。绿林军和赤眉军先后起义。","新朝改制失败天下大乱。"),
D("d2","刘秀以布衣之身起兵，昆阳之战以少胜多，最终恢复汉室。","汉","汉",91,"光武中兴","刘秀出身平民，在昆阳之战中以两万人击败王莽四十二万大军。他建立了东汉，即位为光武帝，开创了光武中兴。","光武中兴再造汉室。"),
D("d3","光武帝释放奴婢、减轻赋税、整顿吏治，使东汉迅速恢复元气。","汉","汉",88,"光武措施","光武帝刘秀采取释放奴婢、减轻赋税、整顿吏治等措施，使东汉迅速恢复。","东汉恢复元气。"),
D("d4","东汉时期蔡伦改进造纸术，这是中国对世界文明的重大贡献。","汉","汉",92,"蔡伦造纸","东汉蔡伦改进了造纸术，用树皮、麻头等原料制造出质优价廉的纸张。造纸术是中国四大发明之一。","造纸术改变世界。"),
D("d5","东汉后期外戚宦官交替专权，政治日益腐败。黄巾起义爆发后，天下再次陷入战乱。","汉","汉",84,"东汉衰落","东汉后期外戚和宦官交替专权，政治腐败。184年黄巾起义爆发后，东汉名存实亡，进入了三国纷争时代。","东汉走向衰落。"),
D("d6","张骞出使西域开辟的丝绸之路在东汉更加繁荣。班超经营西域三十年，使汉朝的影响力远达中亚。","汉","汉",87,"班超经营西域","东汉班超在西域经营三十年，重新打通了丝绸之路。他的使者甘英甚至到达了波斯湾。","丝绸之路持续繁荣。")]),

A("act-12","秦汉遗产",False,"从秦始皇统一六国到东汉灭亡，四百多年的秦汉时期奠定了中国作为统一多民族国家的基本格局。郡县制、丝绸之路、独尊儒术等遗产影响深远。",[N("史","秦汉四百多年的历史奠定了中华文明的基本框架。此后无论天下如何分裂，统一始终是大势所趋。","史"),N("骞","丝绸之路连接了东西方文明。中国的丝绸、瓷器、茶叶通过这条路线传遍世界。","骞")],[
D("d1","秦朝虽然短暂，但它开创的大一统格局和中央集权制度影响了中国两千年。","汉","汉",93,"秦朝遗产","秦朝虽仅存15年，但建立的大一统格局、中央集权制度深刻影响了中国两千年的历史。","秦朝遗产影响深远。"),
D("d2","汉朝是秦朝制度的继承者和完善者。文景之治、武帝盛世、光武中兴，每个时期都有辉煌成就。","汉","汉",90,"汉朝成就","汉朝继承了秦朝的制度框架并加以完善。汉朝的四百年间在政治、经济、文化各方面都取得了辉煌成就。","汉朝成就辉煌灿烂。"),
D("d3","丝绸之路的开辟是东西方文明交流的伟大开端。它的影响远远超出了中国。","汉","汉",92,"丝绸之路","张骞开辟的丝绸之路连接了东西方文明，促进了商品贸易和文化交流。丝绸之路被联合国列为世界文化遗产。","丝路改变世界。"),
D("d4","独尊儒术使儒家思想成为中国文化的主流。虽然后世对此有争议，但它的影响不可否认。","汉","汉",87,"儒学的影响","汉武帝独尊儒术使儒家思想成为中国文化的主流。虽然这一政策限制了思想多样性，但儒家伦理对中国社会的稳定和发展有积极作用。","儒学成为文化主流。"),
D("d5","秦汉时期奠定了中国作为统一多民族国家的基本格局。此后统一成为中国历史的常态。","汉","汉",91,"统一格局","秦汉时期确立的大一统格局成为此后中国历史的基本走向。无论天下如何分裂，统一始终是历史发展的最终趋势。","统一是历史大势。"),
D("d6","从秦皇汉武到丝绸之路，秦汉时期的遗产至今仍在影响着中国和世界。","汉","汉",89,"秦汉遗产","秦汉时期的制度创新（郡县制、官僚制）、文化成就（儒学、史学）和对外交流（丝绸之路）至今仍对中国和世界产生深远影响。","秦汉遗产永续流传。")])
]})

